28	#[derive(Debug, Clone, PartialEq)]
29	pub enum Properties {
30	    TaskCreate(Box<TaskProps>),
31	    TaskUpdate(Box<TaskPatch>),
32	    ChecklistCreate(ChecklistItemProps),
33	    ChecklistUpdate(ChecklistItemPatch),
34	    TagCreate(TagProps),
