88	impl WireObject {
89	    pub fn properties(&self) -> Result<Properties, serde_json::Error> {
90	        match &self.payload {
91	            Properties::Unknown(map) => WireObject::properties_from(
92	                self.operation_type,
93	                self.entity_type.as_ref(),
94	                map.clone(),
95	            ),
96	            other => Ok(other.clone()),
97	        }
98	    }
99	
100	    pub fn properties_map(&self) -> BTreeMap<String, Value> {
101	        match &self.payload {
102	            Properties::TaskCreate(props) => to_map(props),
103	            Properties::TaskUpdate(patch) => to_map(patch),
104	            Properties::ChecklistCreate(props) => to_map(props),
105	            Properties::ChecklistUpdate(patch) => to_map(patch),
106	            Properties::TagCreate(props) => to_map(props),
107	            Properties::TagUpdate(patch) => to_map(patch),
108	            Properties::AreaCreate(props) => to_map(props),
109	            Properties::AreaUpdate(patch) => to_map(patch),
110	            Properties::TombstoneCreate(props) => to_map(props),
111	            Properties::CommandCreate(props) => to_map(props),
112	            Properties::Delete => BTreeMap::new(),
113	            Properties::Ignored(map) => map.clone(),
114	            Properties::Unknown(map) => map.clone(),
115	        }
116	    }
117	
118	    pub fn create(entity_type: EntityType, payload: impl Into<Properties>) -> Self {
119	        let payload =
120	            Self::coerce_known_payload(OperationType::Create, &entity_type, payload.into());
121	        Self {
122	            operation_type: OperationType::Create,
123	            entity_type: Some(entity_type),
124	            payload,
125	        }
126	    }
127	
128	    pub fn update(entity_type: EntityType, payload: impl Into<Properties>) -> Self {
129	        let payload =
130	            Self::coerce_known_payload(OperationType::Update, &entity_type, payload.into());
131	        Self {
132	            operation_type: OperationType::Update,
133	            entity_type: Some(entity_type),
134	            payload,
135	        }
136	    }
137	
138	    pub fn delete(entity_type: EntityType) -> Self {
139	        Self {
140	            operation_type: OperationType::Delete,
141	            entity_type: Some(entity_type),
142	            payload: Properties::Delete,
143	        }
144	    }
145	
146	    fn properties_from(
147	        operation_type: OperationType,
148	        entity_type: Option<&EntityType>,
149	        properties: BTreeMap<String, Value>,
150	    ) -> Result<Properties, serde_json::Error> {
151	        use EntityType::*;
152	        use Properties::*;
153	        let p = properties;
154	
155	        fn parse<T: DeserializeOwned>(
156	            properties: BTreeMap<String, Value>,
157	        ) -> Result<T, serde_json::Error> {
158	            parse_props_from_map(properties)
159	        }
160	
161	        let payload = match operation_type {
162	            OperationType::Delete => Delete,
163	            OperationType::Create => match entity_type {
164	                Some(Task3 | Task4 | Task6) => TaskCreate(Box::new(parse(p)?)),
165	                Some(ChecklistItem | ChecklistItem2 | ChecklistItem3) => ChecklistCreate(parse(p)?),
166	                Some(Tag3 | Tag4) => TagCreate(parse(p)?),
167	                Some(Area2 | Area3) => AreaCreate(parse(p)?),
168	                Some(Tombstone | Tombstone2) => TombstoneCreate(parse(p)?),
169	                Some(Command) => CommandCreate(parse(p)?),
170	                Some(Settings3 | Settings4 | Settings5) => Ignored(p),
171	                _ => Properties::Unknown(p),
172	            },
173	            OperationType::Update => match entity_type {
174	                Some(Task3 | Task4 | Task6) => TaskUpdate(Box::new(parse(p)?)),
175	                Some(ChecklistItem | ChecklistItem2 | ChecklistItem3) => ChecklistUpdate(parse(p)?),
176	                Some(Tag3 | Tag4) => TagUpdate(parse(p)?),
177	                Some(Area2 | Area3) => AreaUpdate(parse(p)?),
178	                Some(Settings3 | Settings4 | Settings5) => Ignored(p),
179	                _ => Properties::Unknown(p),
180	            },
181	            OperationType::Unknown(_) => Properties::Unknown(p),
182	        };
183	
184	        Ok(payload)
185	    }
186	
187	    fn coerce_known_payload(
188	        operation_type: OperationType,
189	        entity_type: &EntityType,
190	        payload: Properties,
191	    ) -> Properties {
192	        match payload {
193	            Properties::Unknown(map) => {
194	                match Self::properties_from(operation_type, Some(entity_type), map.clone()) {
195	                    Ok(parsed) => parsed,
196	                    Err(_) => Properties::Unknown(map),
197	                }
198	            }
199	            other => other,
200	        }
201	    }
202	}
