204	#[derive(Debug, Clone, Serialize, Deserialize)]
205	struct RawWireObject {
206	    #[serde(rename = "t")]
207	    operation_type: OperationType,
208	    #[serde(rename = "e")]
209	    entity_type: Option<EntityType>,
210	    #[serde(rename = "p", default)]
211	    properties: BTreeMap<String, Value>,
212	}
213	
214	impl Serialize for WireObject {
215	    fn serialize<S: Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
216	        let mut state = serializer.serialize_struct("WireObject", 3)?;
217	        state.serialize_field("t", &self.operation_type)?;
218	        state.serialize_field("e", &self.entity_type)?;
219	        state.serialize_field("p", &self.properties_map())?;
220	        state.end()
221	    }
222	}
223	
224	impl<'de> Deserialize<'de> for WireObject {
225	    fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
226	        let raw = RawWireObject::deserialize(deserializer)?;
227	        let payload = WireObject::properties_from(
228	            raw.operation_type,
229	            raw.entity_type.as_ref(),
230	            raw.properties,
231	        )
232	        .map_err(serde::de::Error::custom)?;
233	        Ok(Self {
234	            operation_type: raw.operation_type,
235	            entity_type: raw.entity_type,
236	            payload,
237	        })
238	    }
239	}
