241	fn parse_props_from_map<T: DeserializeOwned>(
242	    properties: BTreeMap<String, Value>,
243	) -> Result<T, serde_json::Error> {
244	    serde_json::from_value(Value::Object(
245	        properties
246	            .into_iter()
247	            .collect::<serde_json::Map<String, Value>>(),
248	    ))
249	}
