251	fn to_map<T: Serialize>(value: &T) -> BTreeMap<String, Value> {
252	    match serde_json::to_value(value) {
253	        Ok(Value::Object(map)) => map.into_iter().collect(),
254	        _ => BTreeMap::new(),
255	    }
256	}
